  // -- SERVICES - Static Services --
  "services.adv.tag":     { ru: "Наши преимущества",    en: "Our Advantages",    ka: "ჩვენი უპირატესობები" },
  "services.adv.title":   { ru: "Что входит в каждый тур", en: "What's Included in Every Tour", ka: "რა შედის ყოველ ტურში" },
  "services.adv.sub":     { ru: "Мы берём на себя всё — от встречи в аэропорту до последнего впечатления. Вы просто наслаждаетесь.", en: "We take care of everything — from airport pickup to the last impression. You just enjoy.", ka: "ყველაფერს ჩვენ ვაკეთებთ — აეროპორტში დახვედრიდან ბოლო შთაბეჭდილებამდე. თქვენ უბრალოდ ისიამოვნეთ." },
  "services.s1.title":    { ru: "Комфортный транспорт",     en: "Comfortable Transport",      ka: "კომფორტული ტრანსპორტი" },
  "services.s1.desc":     { ru: "Современные автомобили и микроавтобусы с кондиционером. Встреча в аэропорту с табличкой и междугородние трансферы.", en: "Modern cars and air-conditioned minibuses. Airport meet-and-greet with a sign and intercity transfers.", ka: "კომფორტული ავტომობილებითა და მიკროავტობუსებით გადაადგილება. ასევე გთავაზობთ აეროპორტში დახვედრას და ტრანსფერებს ქალაქებს შორის." },
  "services.s2.title":    { ru: "Профессиональный гид",     en: "Professional Guide",         ka: "პროფესიონალი გიდი" },
  "services.s2.desc":     { ru: "Опытные гиды, которые хорошо знают Грузию и во время путешествия познакомят вас с её историей и культурой.", en: "Experienced guides who know Georgia well and will introduce you to its history and culture during your journey.", ka: "გამოცდილი გიდები, რომლებიც კარგად იცნობენ საქართველოს და მოგზაურობის დროს გაგაცნობენ მის ისტორიასა და კულტურას." },
  "services.s3.title":    { ru: "Индивидуальный маршрут",   en: "Individual Route",           ka: "ინდივიდუალური მარშრუტი" },
  "services.s3.desc":     { ru: "Разработаем уникальный маршрут под ваши интересы, даты и пожелания. Полная гибкость и внимание к деталям.", en: "We'll develop a unique route based on your interests, dates and preferences. Full flexibility and attention to detail.", ka: "შეგიქმნით უნიკალურ მარშრუტს თქვენი ინტერესების, თარიღებისა და სურვილების მიხედვით. სრული მოქნილობა და დეტალებისადმი ყურადღება." },
  "services.s4.title":    { ru: "Подбор жилья",             en: "Accommodation Selection",    ka: "საცხოვრებლის შერჩევა" },
  "services.s4.desc":     { ru: "Подберём лучшие отели, гостевые дома и уютные апартаменты в любом регионе Грузии по вашим предпочтениям.", en: "We'll select the best hotels, guesthouses and cozy apartments in any region of Georgia according to your preferences.", ka: "შეგირჩევთ საუკეთესო სასტუმროებს, სასტუმრო სახლებსა და კომფორტულ ბინებს საქართველოს ნებისმიერ რეგიონში თქვენი პრეფერენციების მიხედვით." },
  "services.s5.title":    { ru: "Фотосъёмка в туре",        en: "Tour Photography",           ka: "ფოტოგრაფია ტურში" },
  "services.s5.desc":     { ru: "Профессиональный фотограф запечатлит лучшие моменты вашего путешествия на самых живописных локациях Грузии.", en: "A professional photographer will capture the best moments of your trip at the most scenic locations in Georgia.", ka: "პროფესიონალი ფოტოგრაფი საქართველოს ულამაზეს ლოკაციებზე თქვენი მოგზაურობის საუკეთესო მომენტებს დააფიქსირებს." },
  "services.s6.title":    { ru: "Поддержка 24/7",           en: "24/7 Support",               ka: "24/7 მხარდაჭერა" },
  "services.s6.desc":     { ru: "Наш менеджер на связи круглосуточно на протяжении всего вашего путешествия. Решаем любые вопросы мгновенно.", en: "Our manager is available 24/7 throughout your entire trip. We resolve any issues instantly.", ka: "ჩვენი მენეჯერი მთელი მოგზაურობის განმავლობაში 24 საათის მანძილზე ხელმისაწვდომია. ნებისმიერ საკითხს მყისიერად ვწყვეტთ." },

